-- ----------------------------
-- Table structure for route_analysis_task
-- ----------------------------
DROP TABLE IF EXISTS `route_analysis_task`;
CREATE TABLE `route_analysis_task`  (
                                        `task_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '任务ID（UUID）',
                                        `task_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '任务名称',
                                        `user_id` bigint NOT NULL COMMENT '用户ID（关联sys_user.user_id）',
                                        `trajectory_id` bigint NOT NULL COMMENT '轨迹ID（关联route_trajectory_info.trajectory_id）',
                                        `algorithm_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '算法类型（SW_FP GSCM NDTTT DBSCAN）',
                                        `algorithm_params` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '算法参数（JSON格式）',
                                        `task_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '任务状态（0待处理 1处理中 2已完成 3失败 4已取消）',
                                        `progress_percent` int NULL DEFAULT 0 COMMENT '进度百分比',
                                        `start_time` datetime NULL DEFAULT NULL COMMENT '开始时间',
                                        `end_time` datetime NULL DEFAULT NULL COMMENT '结束时间',
                                        `result_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '结果数据（JSON格式）',
                                        `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '错误信息',
                                        `execution_time` int NULL DEFAULT NULL COMMENT '执行时长（秒）',
                                        `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标志（0存在 2删除）',
                                        `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
                                        `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                        `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
                                        `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                        `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
                                        PRIMARY KEY (`task_id`) USING BTREE,
                                        INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
                                        INDEX `idx_trajectory_id`(`trajectory_id` ASC) USING BTREE,
                                        INDEX `idx_algorithm_type`(`algorithm_type` ASC) USING BTREE,
                                        INDEX `idx_task_status`(`task_status` ASC) USING BTREE,
                                        INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
                                        CONSTRAINT `fk_analysis_trajectory` FOREIGN KEY (`trajectory_id`) REFERENCES `route_trajectory_info` (`trajectory_id`) ON DELETE CASCADE ON UPDATE CASCADE,
                                        CONSTRAINT `fk_analysis_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '分析任务表' ROW_FORMAT = DYNAMIC;

