-- ----------------------------
-- Table structure for route_hotspot_zone
-- ----------------------------
DROP TABLE IF EXISTS `route_hotspot_zone`;
CREATE TABLE `route_hotspot_zone`  (
                                       `hotspot_id` bigint NOT NULL AUTO_INCREMENT COMMENT '热点ID',
                                       `hotspot_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '热点名称',
                                       `hotspot_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '热点类型',
                                       `center_latitude` decimal(10, 8) NOT NULL COMMENT '中心纬度',
                                       `center_longitude` decimal(11, 8) NOT NULL COMMENT '中心经度',
                                       `radius` decimal(8, 2) NULL DEFAULT NULL COMMENT '半径（米）',
                                       `visit_count` int NULL DEFAULT 0 COMMENT '访问次数',
                                       `unique_users` int NULL DEFAULT 0 COMMENT '独立用户数',
                                       `peak_hour` varchar(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '高峰时段',
                                       `avg_duration` int NULL DEFAULT NULL COMMENT '平均停留时长（分钟）',
                                       `related_pois` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '关联POI（逗号分隔的ID）',
                                       `hotspot_images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '热点图片（逗号分隔的URL）',
                                       `analysis_task_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '分析任务ID',
                                       `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
                                       `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                       `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
                                       `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                       `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
                                       PRIMARY KEY (`hotspot_id`) USING BTREE,
                                       INDEX `idx_hotspot_type`(`hotspot_type` ASC) USING BTREE,
                                       INDEX `idx_location`(`center_latitude` ASC, `center_longitude` ASC) USING BTREE,
                                       INDEX `idx_visit_count`(`visit_count` ASC) USING BTREE,
                                       INDEX `idx_analysis_task`(`analysis_task_id` ASC) USING BTREE,
                                       CONSTRAINT `fk_hotspot_task` FOREIGN KEY (`analysis_task_id`) REFERENCES `route_analysis_task` (`task_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '热点数据表' ROW_FORMAT = DYNAMIC;

