-- ----------------------------
DROP TABLE IF EXISTS `route_message_record`;
CREATE TABLE `route_message_record`  (
                                         `message_id` bigint NOT NULL AUTO_INCREMENT COMMENT '消息ID',
                                         `sender_id` bigint NOT NULL COMMENT '发送者ID（关联sys_user.user_id）',
                                         `receiver_id` bigint NULL DEFAULT NULL COMMENT '接收者ID（关联sys_user.user_id，系统消息时为空）',
                                         `message_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息标题',
                                         `message_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息内容',
                                         `message_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息类型（SYSTEM系统通知，USER用户私信，RECOMMEND推荐通知）',
                                         `message_images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '消息图片（逗号分隔的URL）',
                                         `related_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '关联对象ID（如轨迹ID、POI ID等）',
                                         `related_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '关联对象类型（TRAJECTORY POI TASK）',
                                         `read_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '阅读状态（0未读 1已读）',
                                         `send_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '发送时间',
                                         `read_time` datetime NULL DEFAULT NULL COMMENT '阅读时间',
                                         `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标志（0存在 1发送者删除 2接收者删除 3双方删除）',
                                         `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
                                         `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                         `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
                                         `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                         `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
                                         PRIMARY KEY (`message_id`) USING BTREE,
                                         INDEX `idx_sender_receiver`(`sender_id` ASC, `receiver_id` ASC) USING BTREE,
                                         INDEX `idx_receiver_id`(`receiver_id` ASC) USING BTREE,
                                         INDEX `idx_message_type`(`message_type` ASC) USING BTREE,
                                         INDEX `idx_read_status`(`read_status` ASC) USING BTREE,
                                         INDEX `idx_send_time`(`send_time` ASC) USING BTREE,
                                         CONSTRAINT `fk_message_receiver` FOREIGN KEY (`receiver_id`) REFERENCES `sys_user` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE,
                                         CONSTRAINT `fk_message_sender` FOREIGN KEY (`sender_id`) REFERENCES `sys_user` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '消息通知表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of route_message_record
-- ----------------------------

-- ----------------------------
-- Table structure for route_poi_detail
-- ----------------------------
DROP TABLE IF EXISTS `route_poi_detail`;
CREATE TABLE `route_poi_detail`  (
                                     `poi_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'POI ID',
                                     `poi_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'POI名称',
                                     `poi_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'POI类型',
                                     `poi_category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'POI分类',
                                     `latitude` decimal(10, 8) NOT NULL COMMENT '纬度',
                                     `longitude` decimal(11, 8) NOT NULL COMMENT '经度',
                                     `address` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '详细地址',
                                     `poi_desc` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'POI描述',
                                     `poi_images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'POI图片（逗号分隔的URL）',
                                     `contact_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '联系电话',
                                     `business_hours` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '营业时间',
                                     `rating` decimal(2, 1) NULL DEFAULT NULL COMMENT '评分（0-5分）',
                                     `contributor_id` bigint NOT NULL COMMENT '贡献者ID（关联sys_user.user_id）',
                                     `data_source` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'USER' COMMENT '数据来源（USER用户贡献，AMAP高德地图）',
                                     `audit_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '审核状态（0待审核 1通过 2拒绝）',
                                     `audit_by` bigint NULL DEFAULT NULL COMMENT '审核人ID',
                                     `audit_time` datetime NULL DEFAULT NULL COMMENT '审核时间',
                                     `audit_remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '审核备注',
                                     `visit_count` int NULL DEFAULT 0 COMMENT '访问次数',
                                     `like_count` int NULL DEFAULT 0 COMMENT '点赞次数',
                                     `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标志（0存在 2删除）',
                                     `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
                                     `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                     `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
                                     `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                     `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
                                     PRIMARY KEY (`poi_id`) USING BTREE,
                                     INDEX `idx_poi_type`(`poi_type` ASC) USING BTREE,
                                     INDEX `idx_location`(`latitude` ASC, `longitude` ASC) USING BTREE,
                                     INDEX `idx_contributor_id`(`contributor_id` ASC) USING BTREE,
                                     INDEX `idx_audit_status`(`audit_status` ASC) USING BTREE,
                                     INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
                                     INDEX `fk_poi_auditor`(`audit_by` ASC) USING BTREE,
                                     CONSTRAINT `fk_poi_auditor` FOREIGN KEY (`audit_by`) REFERENCES `sys_user` (`user_id`) ON DELETE SET NULL ON UPDATE CASCADE,
                                     CONSTRAINT `fk_poi_contributor` FOREIGN KEY (`contributor_id`) REFERENCES `sys_user` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'POI信息表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of route_poi_detail
-- ----------------------------

-- ----------------------------
-- Table structure for route_statistics_summary
-- ----------------------------
DROP TABLE IF EXISTS `route_statistics_summary`;
CREATE TABLE `route_statistics_summary`  (
                                             `stat_id` bigint NOT NULL AUTO_INCREMENT COMMENT '统计ID',
                                             `stat_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '统计类型（POI HOTSPOT USER TRAJECTORY）',
                                             `stat_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '统计键',
                                             `stat_value` decimal(10, 2) NULL DEFAULT NULL COMMENT '统计值',
                                             `stat_count` int NULL DEFAULT 0 COMMENT '统计数量',
                                             `stat_date` date NULL DEFAULT NULL COMMENT '统计日期',
                                             `stat_period` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '统计周期（DAILY WEEKLY MONTHLY）',
                                             `extra_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '扩展数据（JSON格式）',
                                             `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
                                             `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                             `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
                                             `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                             `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
                                             PRIMARY KEY (`stat_id`) USING BTREE,
                                             UNIQUE INDEX `uk_stat_type_key_date`(`stat_type` ASC, `stat_key` ASC, `stat_date` ASC) USING BTREE,
                                             INDEX `idx_stat_type`(`stat_type` ASC) USING BTREE,
                                             INDEX `idx_stat_date`(`stat_date` ASC) USING BTREE,
                                             INDEX `idx_stat_period`(`stat_period` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '统计数据表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of route_statistics_summary
-- ----------------------------

-- ----------------------------
-- Table structure for route_trajectory_info
-- ----------------------------
DROP TABLE IF EXISTS `route_trajectory_info`;
CREATE TABLE `route_trajectory_info`  (
                                          `trajectory_id` bigint NOT NULL AUTO_INCREMENT COMMENT '轨迹ID',
                                          `user_id` bigint NOT NULL COMMENT '用户ID（关联sys_user.user_id）',
                                          `trajectory_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '轨迹名称',
                                          `trajectory_desc` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '轨迹描述',
                                          `start_location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '起点位置',
                                          `end_location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '终点位置',
                                          `total_distance` decimal(10, 2) NULL DEFAULT NULL COMMENT '总距离（公里）',
                                          `total_duration` int NULL DEFAULT NULL COMMENT '总时长（分钟）',
                                          `point_count` int NULL DEFAULT 0 COMMENT '轨迹点数量',
                                          `trajectory_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '轨迹点数据（JSON格式）',
                                          `trajectory_images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '轨迹图片（逗号分隔的URL）',
                                          `trajectory_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '轨迹状态（0正常 1暂停 2完成）',
                                          `is_public` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '是否公开（0否 1是）',
                                          `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '删除标志（0存在 2删除）',
                                          `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
                                          `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                          `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
                                          `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                          `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
                                          PRIMARY KEY (`trajectory_id`) USING BTREE,
                                          INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
                                          INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
                                          INDEX `idx_trajectory_status`(`trajectory_status` ASC) USING BTREE,
                                          CONSTRAINT `fk_trajectory_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '出行轨迹信息表' ROW_FORMAT = DYNAMIC;

